def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    skewness = ((positive_bins - avg_capacity) ** 3).mean() / (np.std(positive_bins) ** 3 + 1e-9) if positive_bins.size > 0 else 0
    decay_rates = np.linspace(0.5, 2, n)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = ((1 - ratio) ** 7) * 1.5 + 0.22
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-ratio * 20) + 0.05
        elif 0.4 < ratio <= 0.7:
            temp = 0.0
            for k in range(1, 12):
                sign = 1 if k % 2 == 1 else -1
                term = sign * (ratio ** (k + 1)) / (k * 1.2)
                temp += term
            score = abs(temp) + 0.07
        else:
            temp = 0.0
            for p in range(1, 15):
                weight = 1 / ((p + 1) ** 1.1)
                sign = (-1) ** p
                temp += sign * (ratio ** (p + 2)) * weight
            score = abs(temp) + 0.12
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 10):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 2.2)
                    influence = norm_diff * weight
                    if neighbor_capacity > avg_capacity + variance:
                        influence *= 1.15
                    elif neighbor_capacity < avg_capacity - variance:
                        influence *= 0.85
                    neighbors_influence += influence
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.65) * (abs(skewness) + 1) + (avg_capacity ** 0.25)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        large_gap = capacity - item
        if large_gap < 0:
            penalty = ((-large_gap) ** 3.2) * 0.35
        elif large_gap > item * 1.5:
            penalty = 0.07 + (large_gap / capacity) * 0.02
        if i % 5 == 0:
            score *= 0.85
            neighbors_influence *= 1.25
            penalty *= 1.05
        elif i % 3 == 0:
            score *= 1.15
            neighbors_influence *= 0.8
        elif i % 2 == 0:
            score *= 0.9
            neighbors_influence *= 1.1
            penalty *= 1.1
        else:
            score *= 1.0
        decay = decay_rates[i]
        priority = (score + neighbors_influence / cap_factor + penalty) * decay
        if priority < 0:
            priority = 0
        if priority > 10:
            priority = 10 + (priority - 10) ** 0.5
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 8
    for i in range(n):
        if i > 0 and i < n - 1:
            left_diff = abs(priorities[i] - priorities[i-1])
            right_diff = abs(priorities[i] - priorities[i+1])
            if left_diff > 2 and right_diff > 2:
                priorities[i] = (priorities[i-1] + priorities[i+1]) / 2
    return priorities
